/*
   Global design system and base styles
   Visual style based on the provided layout: clean, minimalist, editorial, with muted blue-gray header and airy white content area.
*/

/* CSS Reset / Normalization */
* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

html {
    font-size: 16px;
}

body {
    font-family: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    font-weight: 400;
    line-height: 1.5;
    color: #123047;
    background-color: #ffffff;
    text-rendering: optimizeLegibility;
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: #123047;
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

/* Design tokens */
:root {
    /* Color palette */
    --color-primary-1: #6F7F82; /* header blue-gray */
    --color-primary-2: #123047; /* deep navy */

    --color-secondary-1: #8FA0A3;
    --color-secondary-2: #5B6670;

    --color-accent-light: #ffffff;

    --color-neutral-0: #ffffff;
    --color-neutral-100: #E2E5EA;
    --color-neutral-200: #B2B8C2;

    --color-success: #3A7D5D;
    --color-error: #C94A4A;
    --color-warning: #D19A3A;
    --color-info: #4A7BA7;

    --color-text-main: #123047;
    --color-text-muted: #5B6670;
    --color-border-subtle: #E2E5EA;
    --color-border-muted: #B2B8C2;

    /* Typography */
    --font-family-heading: 'DM Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    --font-family-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;

    --font-size-h1: 2rem;      /* 32px */
    --font-size-h2: 1.5rem;    /* 24px */
    --font-size-h3: 1.25rem;   /* 20px */
    --font-size-body: 1rem;    /* 16px */
    --font-size-small: 0.875rem; /* 14px */

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale */
    --space-1: 0.25rem;  /* 4px */
    --space-2: 0.5rem;   /* 8px */
    --space-3: 1rem;     /* 16px */
    --space-4: 1.5rem;   /* 24px */
    --space-5: 2rem;     /* 32px */
    --space-6: 3rem;     /* 48px */
    --space-7: 4rem;     /* 64px */
}

/* Layout helpers */
.layout-container {
    max-width: 1120px;
    margin: 0 auto;
    padding: 0 var(--space-4);
}

.site-main {
    padding-top: var(--space-7);
    padding-bottom: var(--space-7);
}

/* Heading typography */
h1,
h2,
h3,
h4,
h5,
h6 {
    margin: 0 0 var(--space-3);
    font-family: var(--font-family-heading);
    color: var(--color-primary-2);
}

h1 {
    font-size: var(--font-size-h1);
    font-weight: var(--font-weight-semibold);
    line-height: var(--line-height-tight);
}

h2 {
    font-size: var(--font-size-h2);
    font-weight: var(--font-weight-medium);
    line-height: var(--line-height-tight);
}

h3 {
    font-size: var(--font-size-h3);
    font-weight: var(--font-weight-medium);
    line-height: var(--line-height-tight);
}

p {
    margin: 0 0 var(--space-3);
    font-size: var(--font-size-body);
}

small {
    font-size: var(--font-size-small);
}

/* Header and navigation */
.site-header {
    background-color: var(--color-primary-1);
    color: var(--color-accent-light);
}

.header-inner {
    display: flex;
    align-items: center;
    min-height: 72px;
}

.brand {
    display: inline-flex;
    align-items: center;
    padding: var(--space-2) 0;
    margin-right: auto;
    color: var(--color-accent-light);
    text-decoration: none;
}

.brand-mark {
    font-family: var(--font-family-heading);
    font-size: 1.0625rem; /* around 17px */
    font-weight: var(--font-weight-medium);
    letter-spacing: 0.08em;
    text-transform: uppercase;
}

.site-nav {
    flex: 1;
    display: flex;
    justify-content: center;
}

.nav-list {
    list-style: none;
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 2.25rem; /* 36px, similar to design */
    margin: 0;
    padding: 0;
}

.nav-item {
    position: relative;
}

.nav-link {
    position: relative;
    display: inline-block;
    padding-top: 0.75rem;  /* 12px */
    padding-bottom: 0.75rem;
    font-family: var(--font-family-heading);
    font-size: 0.9375rem; /* 15px, slightly refined */
    font-weight: var(--font-weight-medium);
    letter-spacing: 0.04em;
    text-transform: none;
    color: var(--color-accent-light);
    text-decoration: none;
    white-space: nowrap;
}

.nav-link::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    bottom: -0.4rem; /* slight offset below baseline */
    margin: 0 auto;
    height: 2px;
    width: 0;
    background-color: var(--color-accent-light);
    transition: width 160ms ease-out;
}

/* Active state: add .nav-item--active on the current page's item */
.nav-item--active .nav-link::after {
    width: 100%;
}

.nav-link:hover,
.nav-link:focus-visible {
    color: #ffffff;
}

.nav-link:hover::after,
.nav-link:focus-visible::after {
    width: 100%;
}

/* Main content spacing relative to header */
@media (max-width: 768px) {
    .header-inner {
        align-items: flex-start;
        padding-top: var(--space-3);
        padding-bottom: var(--space-3);
        flex-direction: column;
        gap: var(--space-2);
    }

    .brand {
        margin-bottom: var(--space-2);
    }

    .nav-list {
        justify-content: flex-start;
        gap: 1.25rem;
    }

    .site-main {
        padding-top: var(--space-6);
    }
}

/* Form system (for consistency with provided design, used by individual pages) */
label {
    display: block;
    margin-bottom: 0.375rem; /* ~6px */
    font-size: 0.9rem;
    font-weight: var(--font-weight-regular);
    color: var(--color-text-muted);
}

input[type='text'],
input[type='email'],
input[type='tel'],
input[type='number'],
input[type='date'],
input[type='time'],
input[type='password'],
select,
textarea {
    display: block;
    width: 100%;
    padding: 0.55rem 0.75rem; /* vertical 8-12px, horizontal 12px */
    border-radius: 3px;
    border: 1px solid var(--color-border-muted);
    background-color: var(--color-neutral-0);
    font-family: var(--font-family-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-text-main);
    outline: none;
}

input[type='text']:focus,
input[type='email']:focus,
input[type='tel']:focus,
input[type='number']:focus,
input[type='date']:focus,
input[type='time']:focus,
input[type='password']:focus,
select:focus,
textarea:focus {
    border-color: var(--color-primary-2);
}

textarea {
    resize: vertical;
    min-height: 120px;
}

.form-group {
    margin-bottom: 1rem; /* 16px */
}

/* Footer styles */
.site-footer {
    margin-top: var(--space-7);
    background-color: #f7f8fb; /* light neutral to separate from main content */
    color: var(--color-text-muted);
    border-top: 1px solid var(--color-border-subtle);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-5);
    padding-top: var(--space-6);
    padding-bottom: var(--space-5);
}

.footer-branding {
    flex: 1 1 260px;
    max-width: 360px;
}

.footer-brand-mark {
    font-family: var(--font-family-heading);
    font-size: 1rem;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: var(--space-2);
    color: var(--color-primary-2);
}

.footer-text {
    font-size: var(--font-size-body);
    line-height: var(--line-height-relaxed);
    margin: 0;
}

.footer-nav {
    display: flex;
    flex: 2 1 420px;
    gap: var(--space-5);
}

.footer-column {
    min-width: 160px;
}

.footer-heading {
    font-family: var(--font-family-heading);
    font-size: 0.875rem;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.14em;
    text-transform: uppercase;
    margin-bottom: var(--space-3);
    color: var(--color-secondary-2);
}

.footer-link-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.footer-link-list li {
    margin-bottom: 0.5rem;
}

.footer-link-list a {
    font-size: 0.95rem;
    color: var(--color-text-muted);
    text-decoration: none;
}

.footer-link-list a:hover,
.footer-link-list a:focus-visible {
    color: var(--color-primary-2);
    text-decoration: underline;
}

.footer-bottom {
    border-top: 1px solid var(--color-border-subtle);
    padding: var(--space-3) 0;
}

.footer-bottom-inner {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.footer-copy {
    margin: 0;
    font-size: var(--font-size-small);
}

@media (max-width: 768px) {
    .footer-inner {
        flex-direction: column;
        gap: var(--space-4);
    }

    .footer-nav {
        flex-direction: row;
        flex-wrap: wrap;
    }

    .footer-bottom-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-2);
    }
}
